#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000007

// Function to calculate the number of subsets
long long calculateSubsets(int n, int k, int **graph) {
    long long *dp = (long long *)malloc((k + 1) * sizeof(long long));
    dp[0] = 1;
    for (int i = 1; i <= k; i++) {
        dp[i] = (dp[i - 1] * 2) % MOD;
    }
    // Calculate the number of subsets for each connected component
    long long result = 0;
    for (int i = 0; i < n; i++) {
        int size = 0;
        int *component = (int *)malloc(n * sizeof(int));
        // Perform DFS to find the size of the connected component
        dfs(graph, i, &size, component);
        if (size <= k) {
            result = (result + dp[size]) % MOD;
        }
    }
    free(dp);
    return result;
}

// Function to perform DFS
void dfs(int **graph, int node, int *size, int *component) {
    component[*size] = node;
    (*size)++;
    for (int i = 0; i < n; i++) {
        if (graph[node][i] == 1 && !visited[i]) {
            visited[i] = 1;
            dfs(graph, i, size, component);
        }
    }
}

int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        int n, m, k;
        scanf("%d %d %d", &n, &m, &k);
        int **graph = (int **)malloc(n * sizeof(int *));
        for (int i = 0; i < n; i++) {
            graph[i] = (int *)malloc(n * sizeof(int));
            for (int j = 0; j < n; j++) {
                graph[i][j] = 0;
            }
        }
        for (int i = 0; i < m; i++) {
            int u, v;
            scanf("%d %d", &u, &v);
            graph[u - 1][v - 1] = 1;
            graph[v - 1][u - 1] = 1;
        }
        long long result = calculateSubsets(n, k, graph);
        printf("%lld\n", result);
        for (int i = 0; i < n; i++) {
            free(graph[i]);
        }
        free(graph);
    }
    return 0;
}

