import java.util.Scanner;
public class Main {
    static final int MOD = 1000000007;
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int t = sc.nextInt();
        while (t-- > 0) {
            int n = sc.nextInt();
            int m = sc.nextInt();
            int k = sc.nextInt();
            int[][] graph = new int[n][n];
            for (int i = 0; i < m; i++) {
                int u = sc.nextInt() - 1;
                int v = sc.nextInt() - 1;
                graph[u][v] = 1;
                graph[v][u] = 1;
            }
            long result = calculateSubsets(n, k, graph);
            System.out.println(result);
        }
    }

    public static long calculateSubsets(int n, int k, int[][] graph) {
        long[] dp = new long[k + 1];
        dp[0] = 1;
        for (int i = 1; i <= k; i++) {
            dp[i] = (dp[i - 1] * 2) % MOD;
        }
        long result = 0;
        for (int i = 0; i < n; i++) {
            int size = 0;
            int[] component = new int[n];
            // Perform DFS to find the size of the connected component
            dfs(graph, i, size, component);
            if (size <= k) {
                result = (result + dp[size]) % MOD;
            }
        }
        return result;
    }

    public static void dfs(int[][] graph, int node, int size, int[] component) {
        component[size] = node;
        size++;
        for (int i = 0; i < graph.length; i++) {
            if (graph[node][i] == 1 && !visited[i]) {
                visited[i] = true;
                dfs(graph, i, size, component);
            }
        }
    }
}

